#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N], B[N], prefixSum[N + 1];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &B[i]);
    }
    prefixSum[0] = 0;
    for (int i = 0; i < N; i++) {
        prefixSum[i + 1] = prefixSum[i] + A[i];
    }
    for (int i = 0; i < Q; i++) {
        int type, L, R;
        scanf("%d %d", &type, &L);
        if (type == 1) {
            for (int j = L - 1; j < N; j++) {
                A[j] += B[j - L + 1];
            }
            prefixSum[0] = 0;
            for (int j = 0; j < N; j++) {
                prefixSum[j + 1] = prefixSum[j] + A[j];
            }
        } else {
            scanf("%d", &R);
            printf("%d\n", prefixSum[R] - prefixSum[L - 1]);
        }
    }
    return 0;
}

