        int Q = scanner.nextInt();
        int[] A = new int[N];
        int[] B = new int[N];
        int[] prefixSum = new int[N + 1];
        for (int i = 0; i < N; i++) {
            A[i] = scanner.nextInt();
        }
        for (int i = 0; i < N; i++) {
            B[i] = scanner.nextInt();
        }
        prefixSum[0] = 0;
        for (int i = 0; i < N; i++) {
            prefixSum[i + 1] = prefixSum[i] + A[i];
        }
        for (int i = 0; i < Q; i++) {
            int type = scanner.nextInt();
            int L = scanner.nextInt();
            if (type == 1) {
                for (int j = L - 1; j < N; j++) {
                    A[j] += B[j - L + 1];
