const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const N = parseInt(readline().split(' ')[0]);
const Q = parseInt(readline().split(' ')[1]);
const A = readline().split(' ').map(x => parseInt(x));
const B = readline().split(' ').map(x => parseInt(x));
const prefixSum = new Array(N + 1).fill(0);
for (let i = 0; i < N; i++) {
    prefixSum[i + 1] = prefixSum[i] + A[i];
}
for (let i = 0; i < Q; i++) {
    const [type, L] = readline().split(' ').map(x => parseInt(x));
    if (type === 1) {
        for (let j = L - 1; j < N; j++) {
            A[j] += B[j - L + 1];
        }
        prefixSum.fill(0);
        for (let j = 0; j < N; j++) {
            prefixSum[j + 1] = prefixSum[j] + A[j];
        }
    } else {
        const R = parseInt(readline().split(' ')[0]);
        console.log(prefixSum[R] - prefixSum[L - 1]);
    }
}

